def genericParameterLocus {R : Type*} [CommRing R] (m L : ℕ) :
    Set (ParamSpace R m) :=
  bandSupportedParams m L ∩ { θ |
      θ.1 * (∏ i : Fin m, (θ.1 - θ.2.1 i))
        * (∏ i : Fin m, ∏ i' : Fin m, if i < i' then θ.2.1 i - θ.2.1 i' else 1)
        * (∏ j : Fin (m + 2), ∏ r ∈ Finset.Icc 2 L, θ.2.2 j r) ≠ 0 }

