def fiberCorrespondence {R : Type*} [Zero R] (L : ℕ)
    (Φ : ParamSpace R m → CumVec R) (t : CumVec R) : Set (ParamSpace R m) :=
  bandSupportedParams m L ∩
    { θ | ∀ r a : ℕ, 2 ≤ r → r ≤ L → a ≤ r → Φ θ r a = t r a }

