/-- Complexification of a real structural parameter, coordinatewise. -/
def complexifyParam {m : ℕ} (p : ParamSpace ℝ m) : ParamSpace ℂ m :=
  ((p.1 : ℂ), (fun i => (p.2.1 i : ℂ)), (fun j r => (p.2.2 j r : ℂ)))

