aux_admissibleOrbit.statement:
/-- Orbit of `θ` under the admissible source-swap `G_m` action (the admissible
relabelings of the middle latent block). -/
def admissibleOrbit {m : ℕ} (θ : ParamSpace ℂ m) : Set (ParamSpace ℂ m) :=
  { θ' | ∃ π : Equiv.Perm (Fin m), θ' = admissibleSourceSwap m π θ }

aux_bandSupportedParams.statement:
/-- The paper's finite retained-coordinate parameter space, represented inside the
function-valued `ParamSpace` by pinning every off-band source weight to zero. -/
def bandSupportedParams {R : Type*} [Zero R] (m L : ℕ) : Set (ParamSpace R m) :=
  { θ | ∀ (j : Fin (m + 2)) (r : ℕ), (r < 2 ∨ L < r) → θ.2.2 j r = 0 }

