/-- Complexification of a real structural parameter, coordinatewise. -/
def complexifyParam {m : ℕ} (p : ParamSpace ℝ m) : ParamSpace ℂ m :=
  ((p.1 : ℂ), (fun i => (p.2.1 i : ℂ)), (fun j r => (p.2.2 j r : ℂ)))

aux_CumVec.statement:
/-- Observable truncated-cumulant coordinate vector `t ∈ R^{q_L}`, indexed by
`(r, a)` with `2 ≤ r ≤ L`, `0 ≤ a ≤ r`.
@realizes T_L(P),t(coordinate family (r,a) ↦ t_{r,a})
@realizes kappa_{r,a}(P)(coordinate (r,a)) -/
abbrev CumVec (R : Type*) : Type _ := ℕ → ℕ → R

aux_forwardLoading.statement:
/-- Forward source direction family `u_j ∈ R²`:
`u₀ = (1, γ)`, `u_j = (1, ρ_j)` for `1 ≤ j ≤ m`, `u_{m+1} = (0, 1)`.
@realizes u_j(u₀=(1,γ), u_j=(1,ρ_j), u_{m+1}=(0,1)) -/
def forwardLoading {R : Type*} [CommRing R] (m : ℕ) (γ : R) (ρ : Fin m → R) :
    Fin (m + 2) → R × R :=
  fun j =>
    if _ : j.val = 0 then (1, γ)
    else if _ : j.val = m + 1 then (0, 1)
    else (1, ρ ⟨j.val - 1, by have := j.isLt; omega⟩)

aux_genericCompatibilityClosure.statement:
/-- Zariski closure `\bar E_m` of the compatibility locus — the second component
of the compatibility-locus construction `def:generic-full-fiber-compatibility`
(`E_m`, `\bar E_m`, `H^right_m`, `H^left_m`).
@realizes E_m,barE_m,H^right_m,H^left_m(Zariski closure `\bar E_m`) -/
def genericCompatibilityClosure (m : ℕ) : Set (CumVec ℂ) :=
  zariskiClosure (genericFullFiberCompatibility m)

aux_IsPolynomialRankOpen.statement:
/-- A genuine polynomial rank-open locus: a nonempty principal open set cut out
by nonvanishing of a nonzero observable-coordinate minor. -/
def IsPolynomialRankOpen (rankOpen : Set (CumVec ℝ)) : Prop :=
  ∃ minor : MvPolynomial (ℕ × ℕ) ℝ,
    minor ≠ 0 ∧ rankOpen.Nonempty ∧
    rankOpen = { t | MvPolynomial.eval (fun ra => t ra.1 ra.2) minor ≠ 0 }

aux_loadingSlopeMultiset.statement:
/-- The unordered finite-slope part of either arrow support. -/
def loadingSlopeMultiset {m : ℕ} (θ : ParamSpace ℂ m) : Multiset ℂ :=
  θ.1 ::ₘ (Finset.univ.val.map (fun i => θ.2.1 i))

