aux_ProjectivelyEquivalent.statement:
/-- Two nonzero affine representatives determine the same projective direction. -/
def ProjectivelyEquivalent (u v : ℝ × ℝ) : Prop :=
  u ≠ (0, 0) ∧ ∃ c : ℝ, c ≠ 0 ∧ v = (c * u.1, c * u.2)

aux_realAtlasReverseLabel.statement:
/-- Reverse atlas nonemptiness label `ε^left(t)`. -/
def realAtlasReverseLabel (m : ℕ) (t : CumVec ℝ) : Prop :=
  (realAtlasReverseSection m t).Nonempty

aux_reverseLoading.statement:
/-- Reverse source direction family `v_j ∈ R²`:
`v₀ = (1, 0)`, `v_j = (σ_j, 1)` for `1 ≤ j ≤ m`, `v_{m+1} = (δ, 1)`.
@realizes v_j(v₀=(1,0), v_j=(σ_j,1), v_{m+1}=(δ,1)) -/
